    #[test]
    fn rfc9881_keygen() {
        // note: same seed for MLDSA44, MLDSA65, MLDSA87
        let seed = KeyMaterial256::from_bytes_as_type(
            &hex::decode("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
                .unwrap(),
            KeyType::Seed,
        )
        .unwrap();

        /* MLDSA44 */
        let expected_sk_bytes: [u8; MLDSA44_SK_LEN] = hex::decode("").unwrap()
                                                        .try_into().unwrap();
        let expected_pk_bytes: [u8; MLDSA44_PK_LEN] = hex::decode("").unwrap()
                                                        .try_into().unwrap();

        // Decode and re-encode the sk, make sure you get the same thing
        let expected_sk = MLDSA44PrivateKey::from_bytes(&expected_sk_bytes).unwrap();
        let sk_bytes = expected_sk.encode();
        assert_eq!(sk_bytes.len(), expected_sk_bytes.len());
        assert_eq!(sk_bytes, expected_sk_bytes.as_slice());

        // Decode and re-encode the pk, make sure you get the same thing
        let decoded_pk = MLDSA44PublicKey::from_bytes(&expected_pk_bytes).unwrap();
        let pk_bytes = decoded_pk.encode();
        assert_eq!(pk_bytes.len(), expected_pk_bytes.len());
        assert_eq!(pk_bytes, expected_pk_bytes.as_slice());

        // run keygen from seed
        let (derived_pk, derived_sk) = MLDSA44::keygen_from_seed(&seed).unwrap();
        let sk_bytes = derived_sk.encode();

        assert_eq!(sk_bytes.len(), expected_sk_bytes.len());
        assert_eq!(sk_bytes, expected_sk_bytes.as_slice());
        assert_eq!(derived_pk.encode(), expected_pk_bytes.as_slice());
        // also test the `impl Eq`
        assert_eq!(derived_sk, expected_sk);
        assert_eq!(derived_pk, decoded_pk);

        // consistency check between returned pk and sk.get_public_key()
        assert_eq!(derived_pk, derived_sk.derive_pk());

        MLDSA44::keygen_from_seed_and_encoded(&seed, &sk_bytes).unwrap();

        let mut wrong_sk_bytes = sk_bytes.clone();
        wrong_sk_bytes[4..8].copy_from_slice(&[0u8, 0u8, 0u8, 0u8]);
        match MLDSA44::keygen_from_seed_and_encoded(&seed, &wrong_sk_bytes) {
            Err(SignatureError::KeyGenError(_)) => { /* good */ }
            _ => panic!("sk_from_seed_and_encoded should fail with InvalidSignature"),
        }

        /* MLDSA65 */
        let expected_sk_bytes: [u8; MLDSA65_SK_LEN] = hex::decode("").unwrap()
                                                        .try_into().unwrap();
        let expected_pk_bytes: [u8; MLDSA65_PK_LEN] = hex::decode("").unwrap()
                                                        .try_into().unwrap();

        // Decode and re-encode the sk, make sure you get the same thing
        let decoded_sk = MLDSA65PrivateKey::from_bytes(&expected_sk_bytes).unwrap();
        let sk_bytes = decoded_sk.encode();
        assert_eq!(sk_bytes.len(), expected_sk_bytes.len());
        assert_eq!(sk_bytes, expected_sk_bytes.as_slice());

        // Decode and re-encode the pk, make sure you get the same thing
        let expected_pk = MLDSA65PublicKey::from_bytes(&expected_pk_bytes).unwrap();
        let pk_bytes = expected_pk.encode();
        assert_eq!(pk_bytes.len(), expected_pk_bytes.len());
        assert_eq!(pk_bytes, expected_pk_bytes.as_slice());

        // run keygen from seed
        let (derived_pk, derived_sk) = MLDSA65::keygen_from_seed(&seed).unwrap();
        let sk_bytes = derived_sk.encode();

        assert_eq!(sk_bytes.len(), expected_sk_bytes.len());
        assert_eq!(sk_bytes, expected_sk_bytes.as_slice());
        assert_eq!(derived_pk.encode(), expected_pk_bytes.as_slice());
        // also test the `impl Eq`
        assert_eq!(derived_sk, decoded_sk);
        assert_eq!(derived_pk, expected_pk);

        // consistincy check between returned pk and sk.get_public_key()
        assert_eq!(derived_pk, derived_sk.derive_pk());

        MLDSA65::keygen_from_seed_and_encoded(&seed, &sk_bytes).unwrap();

        let mut wrong_sk_bytes = sk_bytes.clone();
        wrong_sk_bytes[4..8].copy_from_slice(&[0u8, 0u8, 0u8, 0u8]);
        match MLDSA65::keygen_from_seed_and_encoded(&seed, &wrong_sk_bytes) {
            Err(SignatureError::KeyGenError(_)) => { /* good */ }
            _ => panic!("sk_from_seed_and_encoded should fail with InvalidSignature"),
        }

        /* MLDSA87 */
        let expected_sk_bytes: [u8; MLDSA87_SK_LEN] = hex::decode("").unwrap()
                                                        .try_into().unwrap();
        let expected_pk_bytes: [u8; MLDSA87_PK_LEN] = hex::decode("").unwrap()
                                                        .try_into().unwrap();

        // Decode and re-encode the sk, make sure you get the same thing
        let decoded_sk = MLDSA87PrivateKey::from_bytes(&expected_sk_bytes).unwrap();
        let sk_bytes = decoded_sk.encode();
        assert_eq!(sk_bytes.len(), expected_sk_bytes.len());
        assert_eq!(sk_bytes, expected_sk_bytes.as_slice());

        // Decode and re-encode the pk, make sure you get the same thing
        let expected_pk = MLDSA87PublicKey::from_bytes(&expected_pk_bytes).unwrap();
        let pk_bytes = expected_pk.encode();
        assert_eq!(pk_bytes.len(), expected_pk_bytes.len());
        assert_eq!(pk_bytes, expected_pk_bytes.as_slice());

        // run keygen from seed
        let (derived_pk, derived_sk) = MLDSA87::keygen_from_seed(&seed).unwrap();
        let sk_bytes = derived_sk.encode();

        assert_eq!(sk_bytes.len(), expected_sk_bytes.len());
        assert_eq!(sk_bytes, expected_sk_bytes.as_slice());
        assert_eq!(derived_pk.encode(), expected_pk_bytes.as_slice());
        // also test the `impl Eq`
        assert_eq!(derived_sk, decoded_sk);
        assert_eq!(derived_pk, expected_pk);

        // consistency check between returned pk and sk.get_public_key()
        assert_eq!(derived_pk, derived_sk.derive_pk());

        MLDSA87::keygen_from_seed_and_encoded(&seed, &sk_bytes).unwrap();

        let mut wrong_sk_bytes = sk_bytes.clone();
        wrong_sk_bytes[4..8].copy_from_slice(&[0u8, 0u8, 0u8, 0u8]);
        match MLDSA87::keygen_from_seed_and_encoded(&seed, &wrong_sk_bytes) {
            Err(SignatureError::KeyGenError(_)) => { /* good */ }
            _ => panic!("sk_from_seed_and_encoded should fail with InvalidSignature"),
        }
    }

    #[test]
    fn keygen_from_rng_tests() {
        /* keygen from seed must match keygen from rng, for a fixed-seed rng */
        // Same arbitrary fixed seed as rfc9881_keygen.
        let seed_bytes: [u8; 32] =
            hex::decode("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
                .unwrap()
                .try_into()
                .unwrap();

        // The seed as fed directly to keygen_from_seed.
        let seed = KeyMaterial256::from_bytes_as_type(&seed_bytes, KeyType::Seed).unwrap();

        // ML-DSA-44
        let (pk_seed, sk_seed) = MLDSA44::keygen_from_seed(&seed).unwrap();
        let mut rng = FixedSeedRNG::new(seed_bytes);
        let (pk_rng, sk_rng) = MLDSA44::keygen_from_rng(&mut rng).unwrap();
        assert_eq!(pk_rng, pk_seed, "ML-DSA-44 pk from RNG must match pk from seed");
        assert_eq!(sk_rng, sk_seed, "ML-DSA-44 sk from RNG must match sk from seed");

        // ML-DSA-65
        let (pk_seed, sk_seed) = MLDSA65::keygen_from_seed(&seed).unwrap();
        let mut rng = FixedSeedRNG::new(seed_bytes);
        let (pk_rng, sk_rng) = MLDSA65::keygen_from_rng(&mut rng).unwrap();
        assert_eq!(pk_rng, pk_seed, "ML-DSA-65 pk from RNG must match pk from seed");
        assert_eq!(sk_rng, sk_seed, "ML-DSA-65 sk from RNG must match sk from seed");

        // ML-DSA-87
        let (pk_seed, sk_seed) = MLDSA87::keygen_from_seed(&seed).unwrap();
        let mut rng = FixedSeedRNG::new(seed_bytes);
        let (pk_rng, sk_rng) = MLDSA87::keygen_from_rng(&mut rng).unwrap();
        assert_eq!(pk_rng, pk_seed, "ML-DSA-87 pk from RNG must match pk from seed");
        assert_eq!(sk_rng, sk_seed, "ML-DSA-87 sk from RNG must match sk from seed");

        /* Test that keygen rejects a seed from a weak RNG */

        // MLDSA44 -- RNG too weak
        let mut rng = FixedSeedRNG::new([0u8; 32]);
        rng.set_security_strength(SecurityStrength::_112bit);
        match MLDSA44::keygen_from_rng(&mut rng) {
            Err(SignatureError::RNGError(RNGError::SecurityStrengthInsufficientForAlgorithm)) => { /* good */
            }
            _ => {
                panic!("should have returned RNGError::RNGSecurityStrengthInsufficientForAlgorithm")
            }
        }

        // MLDSA44 -- RNG just right
        let mut rng = FixedSeedRNG::new([0u8; 32]);
        rng.set_security_strength(SecurityStrength::_128bit);
        _ = MLDSA44::keygen_from_rng(&mut rng).unwrap();

        // MLDSA65 -- RNG too weak
        let mut rng = FixedSeedRNG::new([0u8; 32]);
        rng.set_security_strength(SecurityStrength::_128bit);
        match MLDSA65::keygen_from_rng(&mut rng) {
            Err(SignatureError::RNGError(RNGError::SecurityStrengthInsufficientForAlgorithm)) => { /* good */
            }
            _ => {
                panic!("should have returned RNGError::RNGSecurityStrengthInsufficientForAlgorithm")
            }
        }

        // MLDSA65 -- RNG just right
        let mut rng = FixedSeedRNG::new([0u8; 32]);
        rng.set_security_strength(SecurityStrength::_192bit);
        _ = MLDSA65::keygen_from_rng(&mut rng).unwrap();

        // MLDSA87 -- RNG too weak
        let mut rng = FixedSeedRNG::new([0u8; 32]);
        rng.set_security_strength(SecurityStrength::_192bit);
        match MLDSA87::keygen_from_rng(&mut rng) {
            Err(SignatureError::RNGError(RNGError::SecurityStrengthInsufficientForAlgorithm)) => { /* good */
            }
            _ => {
                panic!("should have returned RNGError::RNGSecurityStrengthInsufficientForAlgorithm")
            }
        }

        // MLDSA87 -- RNG just right
        let mut rng = FixedSeedRNG::new([0u8; 32]);
        rng.set_security_strength(SecurityStrength::_256bit);
        _ = MLDSA87::keygen_from_rng(&mut rng).unwrap();
    }

    #[test]
    fn keygen_error_cases() {
        /*
           Testing this condition:
               if !(seed.key_type() == KeyType::Seed || seed.key_type() == KeyType::BytesFullEntropy)
           || seed.key_len() != 32
        */
        // success case KeyType: seed
        let mut seed = KeyMaterial256::from_bytes_as_type(
            &hex::decode("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
                .unwrap(),
            KeyType::Seed,
        )
        .unwrap();

        /* MLDSA44 */
        let expected_sk_bytes: [u8; MLDSA44_SK_LEN] = hex::decode("").unwrap()
            .try_into().unwrap();
        let expected_pk_bytes: [u8; MLDSA44_PK_LEN] = hex::decode("").unwrap()
            .try_into().unwrap();
        let (derived_pk, derived_sk) = MLDSA44::keygen_from_seed(&seed).unwrap();
        assert_eq!(derived_sk.encode(), expected_sk_bytes.as_slice());
        assert_eq!(derived_pk.encode(), expected_pk_bytes.as_slice());

        // success case KeyType: BytesFullEntropy
        do_hazardous_operations(&mut seed, |seed| seed.set_key_type(KeyType::BytesFullEntropy))
            .unwrap();
        _ = MLDSA44::keygen_from_seed(&seed).unwrap();

        // Failure case: key type != Seed || BytesFullEntropy
        let mac_seed = KeyMaterial256::from_bytes_as_type(
            &hex::decode("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
                .unwrap(),
            KeyType::MACKey,
        )
        .unwrap();

        match MLDSA44::keygen_from_seed(&mac_seed) {
            Err(SignatureError::KeyGenError(_)) => { /* good */ }
            _ => panic!("expected KeyGenError"),
        }

        // Failure case: key is undersized
        let seed = KeyMaterial256::from_bytes_as_type(
            &hex::decode("000102030405060708090a0b0c0d0e0f101112131415161718").unwrap(),
            KeyType::Seed,
        )
        .unwrap();
        assert_eq!(seed.key_len(), 25);

        match MLDSA44::keygen_from_seed(&seed) {
            Err(SignatureError::KeyGenError(_)) => { /* good */ }
            _ => panic!("expected KeyGenError"),
        }
    }

    #[test]
    fn deterministic_sign() {
        // at least one test each of signing with a deterministic signing nonce
        // We support setting the signing nonce (rnd) via two interfaces: external mu, and streaming API.

        // ML-DSA-44

        let sk = MLDSA44PrivateKey::from_bytes(&hex::decode(MLDSA44_KAT1.sk).unwrap()).unwrap();
        let rnd = if !MLDSA44_KAT1.deterministic {
            let mut rnd = [0u8; 32];
            bouncycastle_rng::DefaultRNG::default().next_bytes_out(&mut rnd).unwrap();

            rnd
        } else {
            [0u8; 32]
        };

        let mu = MLDSA44::compute_mu_from_sk(
            &sk,
            &hex::decode(MLDSA44_KAT1.message).unwrap(),
            Some(&hex::decode(MLDSA44_KAT1.ctx).unwrap()),
        )
        .unwrap();
        let sig = MLDSA44::sign_mu_deterministic(&sk, None, &mu, rnd).unwrap();
        assert_eq!(&sig, &*hex::decode(MLDSA44_KAT1.signature).unwrap());
        MLDSA44::verify(
            &sk.derive_pk(),
            &hex::decode(MLDSA44_KAT1.message).unwrap(),
            Some(&hex::decode(MLDSA44_KAT1.ctx).unwrap()),
            &sig,
        )
        .unwrap();

        // test the streaming API on the same value
        let mut s = MLDSA44::sign_init(&sk, Some(&hex::decode(MLDSA44_KAT1.ctx).unwrap())).unwrap();
        s.set_signer_rnd(rnd);
        s.sign_update(&hex::decode(MLDSA44_KAT1.message).unwrap());
        let sig = s.sign_final().unwrap();
        let decoded_sig: [u8; MLDSA44_SIG_LEN] =
            hex::decode(MLDSA44_KAT1.signature).unwrap().try_into().unwrap();
        assert_eq!(&sig, &decoded_sig);

        // Then with the message broken into chunks
        let mut s = MLDSA44::sign_init(&sk, Some(b"streaming API chunked")).unwrap();
        s.set_signer_rnd(rnd);
        for msg_chunk in DUMMY_SEED_1024.chunks(100) {
            s.sign_update(msg_chunk);
        }
        let sig_val = s.sign_final().unwrap();
        MLDSA44::verify(&sk.derive_pk(), DUMMY_SEED_1024, Some(b"streaming API chunked"), &sig_val)
            .unwrap();

        // ML-DSA-65

        let sk = MLDSA65PrivateKey::from_bytes(&hex::decode(MLDSA65_KAT1.sk).unwrap()).unwrap();
        let rnd = if !MLDSA65_KAT1.deterministic {
            let mut rnd = [0u8; 32];
            bouncycastle_rng::DefaultRNG::default().next_bytes_out(&mut rnd).unwrap();
            rnd
        } else {
            [0u8; 32]
        };

        let mu = MLDSA65::compute_mu_from_sk(
            &sk,
            &hex::decode(MLDSA65_KAT1.message).unwrap(),
            Some(&hex::decode(MLDSA65_KAT1.ctx).unwrap()),
        )
        .unwrap();
        let sig = MLDSA65::sign_mu_deterministic(&sk, None, &mu, rnd).unwrap();
        assert_eq!(&sig, &*hex::decode(MLDSA65_KAT1.signature).unwrap());

        MLDSA65::verify(
            &sk.derive_pk(),
            &*hex::decode(MLDSA65_KAT1.message).unwrap(),
            Some(&hex::decode(MLDSA65_KAT1.ctx).unwrap()),
            &sig,
        )
        .unwrap();

        // test the streaming API on the same value
        let mut s = MLDSA65::sign_init(&sk, Some(&hex::decode(MLDSA65_KAT1.ctx).unwrap())).unwrap();
        s.set_signer_rnd(rnd);
        s.sign_update(&hex::decode(MLDSA65_KAT1.message).unwrap());
        let sig = s.sign_final().unwrap();
        let decoded_sig: [u8; MLDSA65_SIG_LEN] =
            hex::decode(MLDSA65_KAT1.signature).unwrap().try_into().unwrap();
        assert_eq!(&sig, &decoded_sig);

        // ML-DSA-87

        let sk = MLDSA87PrivateKey::from_bytes(&hex::decode(MLDSA87_KAT1.sk).unwrap()).unwrap();
        let rnd = if !MLDSA65_KAT1.deterministic {
            let mut rnd = [0u8; 32];
            bouncycastle_rng::DefaultRNG::default().next_bytes_out(&mut rnd).unwrap();
            rnd
        } else {
            [0u8; 32]
        };

        let mu = MLDSA87::compute_mu_from_sk(
            &sk,
            &hex::decode(MLDSA87_KAT1.message).unwrap(),
            Some(&hex::decode(MLDSA87_KAT1.ctx).unwrap()),
        )
        .unwrap();
        let sig = MLDSA87::sign_mu_deterministic(&sk, None, &mu, rnd).unwrap();
        assert_eq!(&sig, &*hex::decode(MLDSA87_KAT1.signature).unwrap());

        MLDSA87::verify(
            &sk.derive_pk(),
            &*hex::decode(MLDSA87_KAT1.message).unwrap(),
            Some(&hex::decode(MLDSA87_KAT1.ctx).unwrap()),
            &sig,
        )
        .unwrap();

        // test the streaming API on the same value
        let mut s = MLDSA87::sign_init(&sk, Some(&hex::decode(MLDSA87_KAT1.ctx).unwrap())).unwrap();
        s.set_signer_rnd(rnd);
        s.sign_update(&hex::decode(MLDSA87_KAT1.message).unwrap());
        let sig = s.sign_final().unwrap();
        let decoded_sig: [u8; MLDSA87_SIG_LEN] =
            hex::decode(MLDSA87_KAT1.signature).unwrap().try_into().unwrap();
        assert_eq!(&sig, &decoded_sig);
    }

    #[test]
    fn test_expanded_key() {
        use bouncycastle_mldsa::{MLDSA44PrivateKeyExpanded, MLDSA44PublicKeyExpanded};
        use bouncycastle_mldsa::{MLDSA65PrivateKeyExpanded, MLDSA65PublicKeyExpanded};
        use bouncycastle_mldsa::{MLDSA87PrivateKeyExpanded, MLDSA87PublicKeyExpanded};

        let msg = b"The quick brown fox jumped over the lazy dog";

        /* ML-DSA-44 */

        let (pk, sk) = MLDSA44::keygen().unwrap();

        let sk_expanded = MLDSA44PrivateKeyExpanded::from(&sk);
        let sig = MLDSA44::sign_with_expanded_key(&sk_expanded, msg, None).unwrap();

        let pk_expanded = MLDSA44PublicKeyExpanded::from(&pk);
        match MLDSA44::verify_with_expanded_key(&pk_expanded, msg, None, &sig) {
            Ok(()) => { /* Signature is valid! */ }
            Err(SignatureError::SignatureVerificationFailed) => println!("Signature is invalid!"),
            Err(e) => panic!("Something else went wrong: {:?}", e),
        }

        /* ML-DSA-65 */

        let (pk, sk) = MLDSA65::keygen().unwrap();

        let sk_expanded = MLDSA65PrivateKeyExpanded::from(&sk);
        let sig = MLDSA65::sign_with_expanded_key(&sk_expanded, msg, None).unwrap();

        let pk_expanded = MLDSA65PublicKeyExpanded::from(&pk);
        match MLDSA65::verify_with_expanded_key(&pk_expanded, msg, None, &sig) {
            Ok(()) => { /* Signature is valid! */ }
            Err(SignatureError::SignatureVerificationFailed) => println!("Signature is invalid!"),
            Err(e) => panic!("Something else went wrong: {:?}", e),
        }

        /* ML-DSA-87 */

        let (pk, sk) = MLDSA87::keygen().unwrap();

        let sk_expanded = MLDSA87PrivateKeyExpanded::from(&sk);
        let sig = MLDSA87::sign_with_expanded_key(&sk_expanded, msg, None).unwrap();

        let pk_expanded = MLDSA87PublicKeyExpanded::from(&pk);
        match MLDSA87::verify_with_expanded_key(&pk_expanded, msg, None, &sig) {
            Ok(()) => { /* Signature is valid! */ }
            Err(SignatureError::SignatureVerificationFailed) => { /* Signature is invalid! */ }
            Err(e) => panic!("Something else went wrong: {:?}", e),
        }

        /* sign_with_expanded_key_out */
        let (pk, sk) = MLDSA44::keygen().unwrap();

        let sk_expanded = MLDSA44PrivateKeyExpanded::from(&sk);
        let mut sig = [0u8; MLDSA44_SIG_LEN];
        let bytes_written =
            MLDSA44::sign_with_expanded_key_out(&sk_expanded, msg, None, &mut sig).unwrap();
        assert_eq!(bytes_written, MLDSA44_SIG_LEN);

        let pk_expanded = MLDSA44PublicKeyExpanded::from(&pk);
        match MLDSA44::verify_with_expanded_key(&pk_expanded, msg, None, &sig) {
            Ok(()) => { /* Signature is valid! */ }
            Err(SignatureError::SignatureVerificationFailed) => println!("Signature is invalid!"),
            Err(e) => panic!("Something else went wrong: {:?}", e),
        }

        /* sign_mu_with_expanded_key_out() */
        let (pk, sk) = MLDSA44::keygen().unwrap();

        let sk_expanded = MLDSA44PrivateKeyExpanded::from(&sk);
        let mut sig = [0u8; MLDSA44_SIG_LEN];
        let bytes_written = MLDSA44::sign_mu_with_expanded_key_out(
            &sk_expanded,
            None,
            &MLDSA44::compute_mu_from_pk(&pk, msg, None).unwrap(),
            &mut sig,
        )
        .unwrap();
        assert_eq!(bytes_written, MLDSA44_SIG_LEN);

        let pk_expanded = MLDSA44PublicKeyExpanded::from(&pk);
        match MLDSA44::verify_with_expanded_key(&pk_expanded, msg, None, &sig) {
            Ok(()) => { /* Signature is valid! */ }
            Err(SignatureError::SignatureVerificationFailed) => println!("Signature is invalid!"),
            Err(e) => panic!("Something else went wrong: {:?}", e),
        }

        // Negative test -- signing with the wrong A_hat gives a signature that doesn't verify
        let (pk, sk) = MLDSA44::keygen().unwrap();
        let (pk1, _sk) = MLDSA44::keygen().unwrap();
        let a_hat1 = pk1.A_hat();

        let mu = MuBuilder::compute_mu(&pk.compute_tr(), msg, None).unwrap();
        let sig = MLDSA44::sign_mu(&sk, Some(&a_hat1), &mu).unwrap();

        let pk_expanded = MLDSA44PublicKeyExpanded::from(&pk);
        match MLDSA44::verify_with_expanded_key(&pk_expanded, msg, None, &sig) {
            Ok(()) => panic!("Signature is valid!"),
            Err(SignatureError::SignatureVerificationFailed) => { /* Signature is invalid! */ }
            Err(e) => panic!("Something else went wrong: {:?}", e),
        }
    }

    #[test]
    fn test_sign_mu_deterministic_from_seed() {
        // I don't have a KAT, so I'll test dynamically against the regular implementation

        // ML-DSA-44

        let seed = KeyMaterial256::from_bytes_as_type(
            &hex::decode("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
                .unwrap(),
            KeyType::Seed,
        )
        .unwrap();

        let rnd = if !MLDSA44_KAT1.deterministic {
            let mut rnd = [0u8; 32];
            bouncycastle_rng::DefaultRNG::default().next_bytes_out(&mut rnd).unwrap();
            rnd
        } else {
            [0u8; 32]
        };

        let tr: [u8; MLDSA_TR_LEN];
        {
            let (_, sk) = MLDSA44::keygen_from_seed(&seed).unwrap();
            tr = sk.tr().clone();
        }

        // BEGIN expected values
        let (_, expected_sk) = MLDSA44::keygen_from_seed(&seed).unwrap();
        let expected_mu = MLDSA44::compute_mu_from_sk(
            &expected_sk,
            &hex::decode(MLDSA44_KAT1.message).unwrap(),
            Some(&hex::decode(MLDSA44_KAT1.ctx).unwrap()),
        )
        .unwrap();
        let mut expected_sig = [0u8; MLDSA44_SIG_LEN];
        let bytes_written = MLDSA44::sign_mu_deterministic_out(
            &expected_sk, None, &expected_mu, rnd, &mut expected_sig,
        )
        .unwrap();
        assert_eq!(bytes_written, MLDSA44_SIG_LEN);
        // END expected values

        let mu = MLDSA44::compute_mu_from_tr(
            &tr,
            &hex::decode(MLDSA44_KAT1.message).unwrap(),
            Some(&hex::decode(MLDSA44_KAT1.ctx).unwrap()),
        )
        .unwrap();
        assert_eq!(&expected_mu, &mu);

        let sig = MLDSA44::sign_mu_deterministic_from_seed(&seed, &mu, rnd).unwrap();
        assert_eq!(&sig, &expected_sig);

        let mut sig = [0u8; MLDSA44_SIG_LEN];
        let bytes_written =
            MLDSA44::sign_mu_deterministic_from_seed_out(&seed, &mu, rnd, &mut sig).unwrap();
        assert_eq!(bytes_written, MLDSA44_SIG_LEN);
        assert_eq!(&sig, &expected_sig);

        let (pk, _) = MLDSA44::keygen_from_seed(&seed).unwrap();
        MLDSA44::verify(
            &pk,
            &hex::decode(MLDSA44_KAT1.message).unwrap(),
            Some(&hex::decode(MLDSA44_KAT1.ctx).unwrap()),
            &sig,
        )
        .unwrap();

        // test invalid seed types
        let wrong_len_seed = KeyMaterial256::from_bytes_as_type(
            &hex::decode("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d").unwrap(),
            KeyType::Seed,
        )
        .unwrap();
        assert_eq!(wrong_len_seed.key_len(), 30);

        match MLDSA44::sign_mu_deterministic_from_seed_out(&wrong_len_seed, &mu, rnd, &mut sig) {
            Err(SignatureError::KeyGenError(_)) => { /* good */ }
            _ => panic!("Expected KeyGenError"),
        };

        let wrong_type_seed = KeyMaterial256::from_bytes_as_type(
            &hex::decode("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
                .unwrap(),
            KeyType::SymmetricCipherKey,
        )
        .unwrap();
        assert_eq!(wrong_type_seed.key_type(), KeyType::SymmetricCipherKey);

        match MLDSA44::sign_mu_deterministic_from_seed_out(&wrong_type_seed, &mu, rnd, &mut sig) {
            Err(SignatureError::KeyGenError(_)) => { /* good */ }
            _ => panic!("Expected KeyGenError"),
        };

        // success case: seed SecurityStrength is exactly right
        let mut low_security_seed = KeyMaterial256::from_bytes_as_type(
            &hex::decode("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
                .unwrap(),
            KeyType::Seed,
        )
        .unwrap();
        do_hazardous_operations(&mut low_security_seed, |low_security_seed| {
            low_security_seed.set_security_strength(SecurityStrength::_192bit)
        })
        .unwrap();
        // a 128bit secure seed should be rejected by MLDSA87
        MLDSA65::sign_mu_deterministic_from_seed(&low_security_seed, &mu, rnd).unwrap();

        // seed SecurityStrength is too low
        let mut low_security_seed = KeyMaterial256::from_bytes_as_type(
            &hex::decode("000102030405060708090a0b0c0d0e0f101112131415161718191a1b1c1d1e1f")
                .unwrap(),
            KeyType::Seed,
        )
        .unwrap();
        do_hazardous_operations(&mut low_security_seed, |low_security_seed| {
            low_security_seed.set_security_strength(SecurityStrength::_128bit)
        })
        .unwrap();
        // a 128bit secure seed should be rejected by MLDSA87
        match MLDSA87::sign_mu_deterministic_from_seed(&low_security_seed, &mu, rnd) {
            Err(SignatureError::KeyGenError(_)) => { /* good */ }
            _ => panic!("Expected KeyGenError"),
        };

        // test the streaming API on the same value

        let mut s =
            MLDSA44::sign_init_from_seed(&seed, Some(&hex::decode(MLDSA44_KAT1.ctx).unwrap()))
                .unwrap();
        s.set_signer_rnd(rnd);
        s.sign_update(&hex::decode(MLDSA44_KAT1.message).unwrap());
        let sig = s.sign_final().unwrap();
        assert_eq!(&sig, &expected_sig);

        // while we're at it, test the streaming verifier cause I'm not sure where else this is being tested.

        let mut v =
            MLDSA44::verify_init(&pk, Some(&hex::decode(MLDSA44_KAT1.ctx).unwrap())).unwrap();
        v.verify_update(&hex::decode(MLDSA44_KAT1.message).unwrap());
        v.verify_final(&expected_sig).unwrap();
    }

    #[test]
    fn test_boundary_conditions() {
        let msg = b"The quick brown fox jumped over the lazy dog";

        // ctx too long
        // this is common to all parameter sets, so I'll just test MLDSA44
        let (_pk, sk) = MLDSA44::keygen().unwrap();

        // ctx with len 255 works
        MLDSA44::sign_init(&sk, Some(&[1u8; 255])).unwrap();

        // ctx with len 256 is too long
        let too_long_ctx = [1u8; 256];
        match MLDSA44::sign_init(&sk, Some(&too_long_ctx)) {
            Err(SignatureError::LengthError(_)) => { /* good */ }
            _ => panic!("Expected error for ctx too long"),
        }

        // test various things that are shorter / longer than required

        // sig too long / too short

        // MLDSA44
        let (pk, sk) = MLDSA44::keygen().unwrap();
        let sig = MLDSA44::sign(&sk, msg, None).unwrap();
        // too short
        match MLDSA44::verify(&pk, msg, None, &sig[..MLDSA44_SIG_LEN - 1]) {
            Err(SignatureError::LengthError(_)) => { /* good */ }
            _ => panic!("Expected error for sig too short"),
        }
        // too long
        let mut sig_too_long = [0u8; MLDSA44_SIG_LEN + 2];
        sig_too_long[..MLDSA44_SIG_LEN].copy_from_slice(&sig);
        sig_too_long[MLDSA44_SIG_LEN..].copy_from_slice(&[1u8, 0u8]);
        match MLDSA44::verify(&pk, msg, None, &sig_too_long) {
            Err(SignatureError::LengthError(_)) => { /* good */ }
            _ => panic!("Expected error for sig too short"),
        }

        // MLDSA65
        let (pk, sk) = MLDSA65::keygen().unwrap();
        let sig = MLDSA65::sign(&sk, msg, None).unwrap();
        // too short
        match MLDSA65::verify(&pk, msg, None, &sig[..MLDSA65_SIG_LEN - 1]) {
            Err(SignatureError::LengthError(_)) => { /* good */ }
            _ => panic!("Expected error for sig too short"),
        }
        // too long
        let mut sig_too_long = [0u8; MLDSA65_SIG_LEN + 2];
        sig_too_long[..MLDSA65_SIG_LEN].copy_from_slice(&sig);
        sig_too_long[MLDSA65_SIG_LEN..].copy_from_slice(&[1u8, 0u8]);
        match MLDSA65::verify(&pk, msg, None, &sig_too_long) {
            Err(SignatureError::LengthError(_)) => { /* good */ }
            _ => panic!("Expected error for sig too short"),
        }

        // MLDSA87
        let (pk, sk) = MLDSA87::keygen().unwrap();
        let sig = MLDSA87::sign(&sk, msg, None).unwrap();
        // too short
        match MLDSA87::verify(&pk, msg, None, &sig[..MLDSA44_SIG_LEN - 1]) {
            Err(SignatureError::LengthError(_)) => { /* good */ }
            _ => panic!("Expected error for sig too short"),
        }
        // too long
        let mut sig_too_long = [0u8; MLDSA87_SIG_LEN + 2];
        sig_too_long[..MLDSA87_SIG_LEN].copy_from_slice(&sig);
        sig_too_long[MLDSA87_SIG_LEN..].copy_from_slice(&[1u8, 0u8]);
        match MLDSA87::verify(&pk, msg, None, &sig_too_long) {
            Err(SignatureError::LengthError(_)) => { /* good */ }
            _ => panic!("Expected error for sig too long"),
        }

        /* GAMMA boundary conditions */

        // test to pin MLDSA65_GAMMA1_MINUS_BETA (produces the wrong sig val if MLDSA65_GAMMA1_MINUS_BETA is wrong)
        let sk = MLDSA65PrivateKey::from_bytes(&hex::decode("").unwrap()).unwrap();
        // because this is from the bc-test-data with busted mu values, need to pin the (busted) mu
        let mu = hex::decode("dd6438e69fdbe810789fb22940fb451c28ac570c8e195f4aebc22db848cabe970a76c92011702d672478fc09f2bdc10b0b7c2b1752a9d99ea7ac3a6381684540").unwrap();
        let expected_sig = hex::decode(
            "",
        ).unwrap();

        let sig =
            MLDSA65::sign_mu_deterministic(&sk, None, mu.as_slice().try_into().unwrap(), [0u8; 32])
                .unwrap();
        assert_eq!(&sig, expected_sig.as_slice());

        // test to pin MLDSA44_GAMMA2_MINUS_BETA (produces the wrong sig val if MLDSA44_GAMMA2_MINUS_BETA is wrong)
        let sk = MLDSA44PrivateKey::from_bytes(&hex::decode("").unwrap()).unwrap();
        // because this is from the bc-test-data with busted mu values, need to fix the (busted) mu
        let mu = hex::decode("35fd0d24022864a6f16159a654290be0c26688439c30c979d14b9553299429cd7c01f9f9835121149c254f2615805f64a32feb0607d87e9417f2900e0d86e351").unwrap();
        let expected_sig = hex::decode(
            "",
        ).unwrap();

        let sig =
            MLDSA44::sign_mu_deterministic(&sk, None, mu.as_slice().try_into().unwrap(), [0u8; 32])
                .unwrap();
        assert_eq!(&sig, expected_sig.as_slice());

        // test to pin MLDSA87_GAMMA2_MINUS_BETA (produces the wrong sig val if MLDSA87_GAMMA2_MINUS_BETA is wrong)
        let sk = MLDSA87PrivateKey::from_bytes(&hex::decode("").unwrap()).unwrap();
        // because this is from the bc-test-data with busted mu values, need to fix the (busted) mu
        let mu = hex::decode("d6961b5a9cc085939e493d4cfabfabb4442604d4058c4bfea3fb5c25cd7a3e4551b34bd9735be6e05925132e0aac4aa374534867289a6af4503baf449e6f6b73").unwrap();
        let expected_sig = hex::decode(
            "",
        ).unwrap();

        let sig =
            MLDSA87::sign_mu_deterministic(&sk, None, mu.as_slice().try_into().unwrap(), [0u8; 32])
                .unwrap();
        assert_eq!(&sig, expected_sig.as_slice());
    }

